import React, { useState, useEffect, useCallback } from 'react';
import { 
    Container, Row, Col, Card, Badge, Button, Modal, 
    Form, Spinner, Alert, InputGroup, ButtonGroup, ListGroup
} from 'react-bootstrap';
import { pedidosService, mesasService } from '../../services/api';
import toast from 'react-hot-toast';

const CuentasPendientes = () => {
    const [mesasConCuentas, setMesasConCuentas] = useState([]);
    const [loading, setLoading] = useState(true);
    const [showPagoModal, setShowPagoModal] = useState(false);
    const [cuentaSeleccionada, setCuentaSeleccionada] = useState(null);
    const [metodoPago, setMetodoPago] = useState('efectivo');
    const [montoRecibido, setMontoRecibido] = useState('');
    const [observacionesPago, setObservacionesPago] = useState('');
    const [procesandoPago, setProcesandoPago] = useState(false);
    const [filtroMonto, setFiltroMonto] = useState('todos'); // 'todos', 'menores', 'mayores'
    const [estadisticas, setEstadisticas] = useState({
        total_mesas: 0,
        total_a_cobrar: 0,
        promedio_cuenta: 0,
        mesa_mayor: null
    });

    const fetchMesasConCuentas = useCallback(async () => {
        try {
            // Simulación de datos para desarrollo - reemplazar con API real
            const mesasConCuentasData = [
                {
                    mesa: { id: 1, numero: 5, capacidad: 4, estado: 'cuenta_solicitada' },
                    cuenta: {
                        mesa: { id: 1, numero: 5, capacidad: 4 },
                        pedidos: [
                            {
                                id: 1,
                                total: 45.90,
                                created_at: new Date(Date.now() - 30 * 60000).toISOString(),
                                mozo: { nombre: 'Juan Pérez' },
                                detalles: [
                                    { cantidad: 1, producto: { nombre: 'Pizza Margarita' }, subtotal: 25.90 },
                                    { cantidad: 2, producto: { nombre: 'Coca Cola' }, subtotal: 7.00 },
                                    { cantidad: 1, producto: { nombre: 'Tiramisú' }, subtotal: 13.00 }
                                ]
                            }
                        ],
                        resumen: {
                            total_pedidos: 1,
                            total_items: 4,
                            total_general: 45.90
                        }
                    }
                },
                {
                    mesa: { id: 2, numero: 3, capacidad: 2, estado: 'cuenta_solicitada' },
                    cuenta: {
                        mesa: { id: 2, numero: 3, capacidad: 2 },
                        pedidos: [
                            {
                                id: 2,
                                total: 28.50,
                                created_at: new Date(Date.now() - 45 * 60000).toISOString(),
                                mozo: { nombre: 'María García' },
                                detalles: [
                                    { cantidad: 1, producto: { nombre: 'Hamburguesa' }, subtotal: 18.50 },
                                    { cantidad: 2, producto: { nombre: 'Agua Mineral' }, subtotal: 4.00 },
                                    { cantidad: 1, producto: { nombre: 'Café' }, subtotal: 6.00 }
                                ]
                            }
                        ],
                        resumen: {
                            total_pedidos: 1,
                            total_items: 4,
                            total_general: 28.50
                        }
                    }
                },
                {
                    mesa: { id: 3, numero: 8, capacidad: 6, estado: 'cuenta_solicitada' },
                    cuenta: {
                        mesa: { id: 3, numero: 8, capacidad: 6 },
                        pedidos: [
                            {
                                id: 3,
                                total: 89.40,
                                created_at: new Date(Date.now() - 60 * 60000).toISOString(),
                                mozo: { nombre: 'Carlos López' },
                                detalles: [
                                    { cantidad: 2, producto: { nombre: 'Pizza Margarita' }, subtotal: 51.80 },
                                    { cantidad: 4, producto: { nombre: 'Coca Cola' }, subtotal: 14.00 },
                                    { cantidad: 2, producto: { nombre: 'Ensalada César' }, subtotal: 24.00 }
                                ]
                            }
                        ],
                        resumen: {
                            total_pedidos: 1,
                            total_items: 8,
                            total_general: 89.40
                        }
                    }
                }
            ];

            // Aplicar filtros
            let mesasFiltradas = mesasConCuentasData;
            if (filtroMonto === 'menores') {
                mesasFiltradas = mesasConCuentasData.filter(m => m.cuenta.resumen.total_general < 50);
            } else if (filtroMonto === 'mayores') {
                mesasFiltradas = mesasConCuentasData.filter(m => m.cuenta.resumen.total_general >= 50);
            }

            setMesasConCuentas(mesasFiltradas);

            // Calcular estadísticas
            const totalACobrar = mesasConCuentasData.reduce((sum, m) => sum + m.cuenta.resumen.total_general, 0);
            const mesaMayor = mesasConCuentasData.reduce((max, m) => 
                m.cuenta.resumen.total_general > (max?.cuenta.resumen.total_general || 0) ? m : max, 
                null
            );

            setEstadisticas({
                total_mesas: mesasConCuentasData.length,
                total_a_cobrar: totalACobrar,
                promedio_cuenta: mesasConCuentasData.length > 0 ? totalACobrar / mesasConCuentasData.length : 0,
                mesa_mayor: mesaMayor
            });

        } catch (error) {
            console.error('Error fetching cuentas pendientes:', error);
            toast.error('Error al cargar cuentas pendientes');
        } finally {
            setLoading(false);
        }
    }, [filtroMonto]);

    useEffect(() => {
        fetchMesasConCuentas();
        
        // Auto-refresh cada 30 segundos
        const interval = setInterval(fetchMesasConCuentas, 30000);
        return () => clearInterval(interval);
    }, [fetchMesasConCuentas]);

    const handleAbrirModalPago = useCallback((mesaConCuenta) => {
        setCuentaSeleccionada(mesaConCuenta);
        setMontoRecibido(mesaConCuenta.cuenta.resumen.total_general.toString());
        setMetodoPago('efectivo');
        setObservacionesPago('');
        setShowPagoModal(true);
    }, []);

    const handleProcesarPago = useCallback(async () => {
        if (!cuentaSeleccionada) return;

        const totalACobrar = cuentaSeleccionada.cuenta.resumen.total_general;
        const montoIngresado = parseFloat(montoRecibido) || 0;

        // Validaciones
        if (metodoPago === 'efectivo' && montoIngresado < totalACobrar) {
            toast.error('El monto recibido debe ser mayor o igual al total');
            return;
        }

        setProcesandoPago(true);
        try {
            // Simular procesamiento de pago
            await new Promise(resolve => setTimeout(resolve, 2000));

            const cambio = metodoPago === 'efectivo' ? Math.max(0, montoIngresado - totalACobrar) : 0;
            
            toast.success(
                `¡Pago procesado exitosamente! ${cambio > 0 ? `Cambio: $${cambio.toFixed(2)}` : ''}`,
                { duration: 6000 }
            );

            // Remover mesa de la lista
            setMesasConCuentas(prev => prev.filter(m => m.mesa.id !== cuentaSeleccionada.mesa.id));
            
            setShowPagoModal(false);
            fetchMesasConCuentas();

        } catch (error) {
            console.error('Error processing payment:', error);
            toast.error('Error al procesar el pago');
        } finally {
            setProcesandoPago(false);
        }
    }, [cuentaSeleccionada, metodoPago, montoRecibido, observacionesPago, fetchMesasConCuentas]);

    const calcularCambio = useCallback(() => {
        if (!cuentaSeleccionada || metodoPago !== 'efectivo') return 0;
        const totalACobrar = cuentaSeleccionada.cuenta.resumen.total_general;
        const montoIngresado = parseFloat(montoRecibido) || 0;
        return Math.max(0, montoIngresado - totalACobrar);
    }, [cuentaSeleccionada, metodoPago, montoRecibido]);

    const calcularTiempoEspera = useCallback((fecha) => {
        const ahora = new Date();
        const inicio = new Date(fecha);
        const diferencia = Math.floor((ahora - inicio) / 1000 / 60); // minutos
        
        if (diferencia < 1) return 'Recién';
        if (diferencia < 60) return `${diferencia} min`;
        
        const horas = Math.floor(diferencia / 60);
        const minutos = diferencia % 60;
        return `${horas}h ${minutos}m`;
    }, []);

    if (loading) {
        return (
            <Container>
                <div className="text-center py-5">
                    <Spinner animation="border" variant="success" size="lg" />
                    <p className="mt-3 h5">Cargando cuentas pendientes...</p>
                </div>
            </Container>
        );
    }

    return (
        <Container fluid>
            {/* Header */}
            <Row className="mb-4">
                <Col>
                    <div className="d-flex justify-content-between align-items-center mb-3">
                        <div>
                            <h2 className="mb-1">
                                <i className="fas fa-cash-register text-success me-2"></i>
                                Cuentas por Cobrar
                            </h2>
                            <p className="text-muted mb-0">
                                Gestiona los pagos de las mesas
                            </p>
                        </div>
                        
                        <div className="d-flex gap-2">
                            <ButtonGroup size="sm">
                                <Button 
                                    variant={filtroMonto === 'todos' ? 'primary' : 'outline-primary'}
                                    onClick={() => setFiltroMonto('todos')}
                                >
                                    Todas
                                </Button>
                                <Button 
                                    variant={filtroMonto === 'menores' ? 'primary' : 'outline-primary'}
                                    onClick={() => setFiltroMonto('menores')}
                                >
                                    &lt; $50
                                </Button>
                                <Button 
                                    variant={filtroMonto === 'mayores' ? 'primary' : 'outline-primary'}
                                    onClick={() => setFiltroMonto('mayores')}
                                >
                                    ≥ $50
                                </Button>
                            </ButtonGroup>
                        </div>
                    </div>

                    {/* Estadísticas */}
                    <Row>
                        <Col md={3}>
                            <Card className="border-0 shadow-sm bg-primary bg-opacity-10">
                                <Card.Body className="text-center py-3">
                                    <i className="fas fa-table fa-2x text-primary mb-2"></i>
                                    <div className="h3 mb-0 text-primary">{estadisticas.total_mesas}</div>
                                    <div className="small text-muted">Mesas Pendientes</div>
                                </Card.Body>
                            </Card>
                        </Col>
                        <Col md={3}>
                            <Card className="border-0 shadow-sm bg-success bg-opacity-10">
                                <Card.Body className="text-center py-3">
                                    <i className="fas fa-dollar-sign fa-2x text-success mb-2"></i>
                                    <div className="h3 mb-0 text-success">${estadisticas.total_a_cobrar.toFixed(2)}</div>
                                    <div className="small text-muted">Total a Cobrar</div>
                                </Card.Body>
                            </Card>
                        </Col>
                        <Col md={3}>
                            <Card className="border-0 shadow-sm bg-info bg-opacity-10">
                                <Card.Body className="text-center py-3">
                                    <i className="fas fa-chart-line fa-2x text-info mb-2"></i>
                                    <div className="h3 mb-0 text-info">${estadisticas.promedio_cuenta.toFixed(2)}</div>
                                    <div className="small text-muted">Promedio por Mesa</div>
                                </Card.Body>
                            </Card>
                        </Col>
                        <Col md={3}>
                            <Card className="border-0 shadow-sm bg-warning bg-opacity-10">
                                <Card.Body className="text-center py-3">
                                    <i className="fas fa-crown fa-2x text-warning mb-2"></i>
                                    <div className="h3 mb-0 text-warning">
                                        Mesa {estadisticas.mesa_mayor?.mesa.numero || '-'}
                                    </div>
                                    <div className="small text-muted">Cuenta Mayor</div>
                                </Card.Body>
                            </Card>
                        </Col>
                    </Row>
                </Col>
            </Row>

            {/* Lista de cuentas */}
            {mesasConCuentas.length === 0 ? (
                <Row>
                    <Col>
                        <Card className="border-0 shadow-sm">
                            <Card.Body className="text-center py-5">
                                <i className="fas fa-check-circle fa-4x text-success mb-4"></i>
                                <h4>¡Excelente trabajo! 🎉</h4>
                                <p className="text-muted mb-0">
                                    No hay cuentas pendientes por cobrar.
                                </p>
                            </Card.Body>
                        </Card>
                    </Col>
                </Row>
            ) : (
                <Row>
                    {mesasConCuentas.map((mesaConCuenta) => (
                        <Col lg={4} md={6} key={mesaConCuenta.mesa.id} className="mb-4">
                            <Card className="h-100 border-0 shadow-sm border-warning border-2">
                                <Card.Header className="bg-warning text-white">
                                    <Row className="align-items-center">
                                        <Col>
                                            <h5 className="mb-0">
                                                <i className="fas fa-table me-2"></i>
                                                Mesa {mesaConCuenta.mesa.numero}
                                            </h5>
                                            <small className="opacity-75">
                                                {mesaConCuenta.mesa.capacidad} personas • {' '}
                                                {calcularTiempoEspera(mesaConCuenta.cuenta.pedidos[0]?.created_at)} esperando
                                            </small>
                                        </Col>
                                        <Col xs="auto">
                                            <Badge bg="light" text="dark" className="px-2 py-1">
                                                {mesaConCuenta.cuenta.resumen.total_items} items
                                            </Badge>
                                        </Col>
                                    </Row>
                                </Card.Header>

                                <Card.Body>
                                    <div className="mb-3">
                                        <div className="d-flex justify-content-between align-items-center mb-2">
                                            <strong className="text-muted small">CONSUMO:</strong>
                                            <span className="badge bg-light text-dark">
                                                {mesaConCuenta.cuenta.resumen.total_pedidos} pedido(s)
                                            </span>
                                        </div>

                                        <div className="bg-light p-3 rounded">
                                            {mesaConCuenta.cuenta.pedidos.map((pedido) => (
                                                <div key={pedido.id} className="mb-2">
                                                    <div className="d-flex justify-content-between align-items-center mb-1">
                                                        <small className="fw-bold">
                                                            Pedido #{pedido.id}
                                                        </small>
                                                        <small className="text-success fw-bold">
                                                            ${parseFloat(pedido.total).toFixed(2)}
                                                        </small>
                                                    </div>
                                                    {pedido.detalles?.slice(0, 3).map((detalle, index) => (
                                                        <div key={index} className="small text-muted d-flex justify-content-between">
                                                            <span>
                                                                {detalle.cantidad}x {detalle.producto.nombre}
                                                            </span>
                                                            <span>${parseFloat(detalle.subtotal).toFixed(2)}</span>
                                                        </div>
                                                    ))}
                                                    {pedido.detalles?.length > 3 && (
                                                        <div className="small text-muted text-center mt-1">
                                                            ... y {pedido.detalles.length - 3} más
                                                        </div>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    <div className="mb-3">
                                        <div className="d-flex justify-content-between">
                                            <strong className="text-muted small">MOZO:</strong>
                                            <span>{mesaConCuenta.cuenta.pedidos[0]?.mozo?.nombre || 'N/A'}</span>
                                        </div>
                                        <div className="d-flex justify-content-between">
                                            <strong className="text-muted small">HORA:</strong>
                                            <span>
                                                {new Date(mesaConCuenta.cuenta.pedidos[0]?.created_at).toLocaleTimeString()}
                                            </span>
                                        </div>
                                    </div>

                                    <hr />

                                    <div className="d-flex justify-content-between align-items-center mb-3">
                                        <strong className="h5 mb-0">TOTAL:</strong>
                                        <strong className="h4 mb-0 text-success">
                                            ${mesaConCuenta.cuenta.resumen.total_general.toFixed(2)}
                                        </strong>
                                    </div>

                                    <div className="d-grid">
                                        <Button
                                            variant="success"
                                            size="lg"
                                            className="fw-bold"
                                            onClick={() => handleAbrirModalPago(mesaConCuenta)}
                                        >
                                            <i className="fas fa-credit-card me-2"></i>
                                            Procesar Pago
                                        </Button>
                                    </div>
                                </Card.Body>
                            </Card>
                        </Col>
                    ))}
                </Row>
            )}

            {/* Modal de procesamiento de pago */}
            <Modal show={showPagoModal} onHide={() => setShowPagoModal(false)} size="lg" centered>
                <Modal.Header closeButton>
                    <Modal.Title>
                        <i className="fas fa-credit-card me-2"></i>
                        Procesar Pago - Mesa {cuentaSeleccionada?.mesa.numero}
                    </Modal.Title>
                </Modal.Header>
                <Modal.Body>
                    {cuentaSeleccionada && (
                        <>
                            {/* Resumen de cuenta */}
                            <div className="bg-light p-3 rounded mb-4">
                                <h6 className="mb-3">Resumen de Cuenta:</h6>
                                <ListGroup variant="flush">
                                    {cuentaSeleccionada.cuenta.pedidos.map((pedido) => (
                                        <ListGroup.Item key={pedido.id} className="px-0">
                                            <div className="d-flex justify-content-between">
                                                <span>Pedido #{pedido.id}</span>
                                                <span className="fw-bold">${parseFloat(pedido.total).toFixed(2)}</span>
                                            </div>
                                        </ListGroup.Item>
                                    ))}
                                </ListGroup>
                                <div className="border-top pt-2 mt-2">
                                    <div className="d-flex justify-content-between">
                                        <strong>TOTAL A COBRAR:</strong>
                                        <strong className="text-success h5">
                                            ${cuentaSeleccionada.cuenta.resumen.total_general.toFixed(2)}
                                        </strong>
                                    </div>
                                </div>
                            </div>

                            {/* Método de pago */}
                            <Form>
                                <Form.Group className="mb-3">
                                    <Form.Label className="fw-bold">Método de Pago:</Form.Label>
                                    <div className="d-flex gap-2">
                                        <Button
                                            variant={metodoPago === 'efectivo' ? 'success' : 'outline-success'}
                                            onClick={() => setMetodoPago('efectivo')}
                                            className="flex-fill"
                                        >
                                            <i className="fas fa-money-bill me-2"></i>
                                            Efectivo
                                        </Button>
                                        <Button
                                            variant={metodoPago === 'tarjeta' ? 'primary' : 'outline-primary'}
                                            onClick={() => setMetodoPago('tarjeta')}
                                            className="flex-fill"
                                        >
                                            <i className="fas fa-credit-card me-2"></i>
                                            Tarjeta
                                        </Button>
                                        <Button
                                            variant={metodoPago === 'transferencia' ? 'info' : 'outline-info'}
                                            onClick={() => setMetodoPago('transferencia')}
                                            className="flex-fill"
                                        >
                                            <i className="fas fa-mobile-alt me-2"></i>
                                            Transferencia
                                        </Button>
                                    </div>
                                </Form.Group>

                                {metodoPago === 'efectivo' && (
                                    <Form.Group className="mb-3">
                                        <Form.Label className="fw-bold">Monto Recibido:</Form.Label>
                                        <InputGroup size="lg">
                                            <InputGroup.Text>$</InputGroup.Text>
                                            <Form.Control
                                                type="number"
                                                step="0.01"
                                                value={montoRecibido}
                                                onChange={(e) => setMontoRecibido(e.target.value)}
                                                placeholder="0.00"
                                                className="fw-bold text-center"
                                            />
                                        </InputGroup>
                                        {calcularCambio() > 0 && (
                                            <div className="mt-2 p-2 bg-info bg-opacity-10 rounded">
                                                <div className="d-flex justify-content-between">
                                                    <span>Cambio a entregar:</span>
                                                    <strong className="text-info h5">
                                                        ${calcularCambio().toFixed(2)}
                                                    </strong>
                                                </div>
                                            </div>
                                        )}
                                    </Form.Group>
                                )}

                                <Form.Group className="mb-3">
                                    <Form.Label>Observaciones (opcional):</Form.Label>
                                    <Form.Control
                                        as="textarea"
                                        rows={2}
                                        value={observacionesPago}
                                        onChange={(e) => setObservacionesPago(e.target.value)}
                                        placeholder="Notas sobre el pago..."
                                    />
                                </Form.Group>
                            </Form>
                        </>
                    )}
                </Modal.Body>
                <Modal.Footer>
                    <Button variant="secondary" onClick={() => setShowPagoModal(false)}>
                        Cancelar
                    </Button>
                    <Button 
                        variant="success" 
                        size="lg"
                        onClick={handleProcesarPago}
                        disabled={procesandoPago || (metodoPago === 'efectivo' && parseFloat(montoRecibido) < cuentaSeleccionada?.cuenta.resumen.total_general)}
                        className="px-4"
                    >
                        {procesandoPago ? (
                            <>
                                <Spinner animation="border" size="sm" className="me-2" />
                                Procesando...
                            </>
                        ) : (
                            <>
                                <i className="fas fa-check me-2"></i>
                                Confirmar Pago
                            </>
                        )}
                    </Button>
                </Modal.Footer>
            </Modal>
        </Container>
    );
};

export default CuentasPendientes;
